As I can see - _pickle_method written for python3 and need few changes:

    def _pickle_method(method):
        """Pickle methods properly, including class methods."""
        if six.PY3:
            func_name = method.__func__.__name__
            obj = method.__self__
            cls = obj.__class__
        else:
            func_name = method.im_func.__name__
            obj = method.im_self
            cls = method.im_class
        if isinstance(cls, type):
            # handle classmethods differently
            cls = obj
            obj = None
        if func_name.startswith('__') and not func_name.endswith('__'):
            #deal with mangled names
            cls_name = cls.__name__.lstrip('_')
            func_name = '_%s%s' % (cls_name, func_name)
        return _unpickle_method, (func_name, obj, cls)

    def _unpickle_method(func_name, obj, cls):
        """Unpickle methods properly, including class methods."""
        if six.PY3:
            if obj is None:
            obj = cls
            cls = cls.__class__
            for cls in cls.__mro__:
            try:
                func = cls.__dict__[func_name]
            except KeyError:
                pass
            else:
                break
            return func.__get__(obj, cls)
        else:
            if obj is None:
            return cls.__dict__[func_name].__get__(obj, cls)
            for cls in cls.__mro__:
            try:
                func = cls.__dict__[func_name]
            except KeyError:
                pass
            else:
                break
            return func.__get__(obj, cls)

