```

That's a whole lot of properties that are not in `properties`. Many tools (noticed it with `fio cat`) will drop this "extraneous" info. **Should the SDK normalize this by putting the non-GeoJSON keys into properties**? Maybe an optional flag `--use-properties`?

```json
{
  "id": "place.39347",
  "properties": {
      "type": "Feature",
      "text": "Portland",
      "place_name": "Portland, Oregon, United States",
      "relevance": 0.998,
      "center": [-122.6742, 45.5202],
      "context": [
        {
          "id": "postcode.1060401628",
          "text": "97204"
        },
        {
          "id": "region.3470299826",
          "text": "Oregon"
        },
        {
          "id": "country.4150104525",
          "text": "United States",
          "short_code": "us"
        }
      ]
  },
  "bbox": [
    -122.9292140099711,
    45.37948199034149,
    -122.44106199104115,
    45.858097009742835
  ],
  "geometry": {
    "type": "Point",
    "coordinates": [
      -122.6742,
      45.5202
    ]
  }
}

