00272	// Unlike the Caffe and Theano GPU verions, the data_im array is set to zero
00273	// before the col2im call rather than doing it here. So, the result is just
00274	// accumulated into data_im.
00275	void col2im(const npy_double* data_col, const int channels,
00276	    const int height, const int width, const int patch_h, const int patch_w,
00277	    const int pad_h, const int pad_w, const int stride_h,
00278	    const int stride_w, npy_double* data_im) {
00279	  int height_col = (height + 2 * pad_h - patch_h) / stride_h + 1;
00280	  int width_col = (width + 2 * pad_w - patch_w) / stride_w + 1;
00281	  int num_kernels = channels * height * width;
00282	  int channels_col = channels * patch_h * patch_w;
00283	  for (int c = 0; c < channels_col; ++c) {
00284	    int w_offset = c % patch_w;
00285	    int h_offset = (c / patch_w) % patch_h;
00286	    int c_im = c / patch_h / patch_w;
00287	    for (int h = 0; h < height_col; ++h) {
00288	      for (int w = 0; w < width_col; ++w) {
00289	        int h_pad = h * stride_h - pad_h + h_offset;
00290	        int w_pad = w * stride_w - pad_w + w_offset;
00291	        if (h_pad >= 0 && h_pad < height && w_pad >= 0 && w_pad < width)
00292	          data_im[(npy_intp)(c_im * height + h_pad) * width + w_pad] +=
00293	            data_col[(npy_intp)(c * height_col + h) * width_col + w];
00294	
00295	      }
00296	    }
00297	  }
00298	}
